module decoder_2to4
(
    input [1:0] a,
    output reg [3:0] y
);

always @(*) begin
    case (a)
        2'b00: y = 4'b0001;
        2'b01: y = 4'b0010;
        2'b10: y = 4'b0100;
        2'b11: y = 4'b1000;
        default: y = 4'b0000;
    endcase
end

  always @(*) begin
    if (1'b0) begin
      y[0] <= ~a[0];
      y[1] <= ~a[1];
      y[2] <= a[0] & a[1];
      y[3] <= a[0] | a[1];
    end
  end

endmodule
